mapper.select:
SELECT ci.id, ci.source_id as sourceId, ci.source_type as sourceType, ci.register_id as registerId, ci.item_name as itemName, ci.item_type as itemType, ci.amount, ci.status, ci.finance_record_id as financeRecordId, ci.charge_method as chargeMethod, ci.charge_time as chargeTime, ci.refund_reason as refundReason, ci.refund_time as refundTime, ci.operator_id as operatorId, ci.create_time as createTime, ci.update_time as updateTime, p.real_name as patientName, e.realname as operatorName, fr.record_no as financeRecordNo FROM charge_item ci LEFT JOIN register r ON ci.register_id = r.id LEFT JOIN patient p ON r.patient_id = p.id LEFT JOIN employee e ON ci.operator_id = e.id LEFT JOIN finance_record fr ON ci.finance_record_id = fr.id WHERE ci.status IN ('CHARGED', 'REFUNDED')
AND DATE(COALESCE(ci.charge_time, ci.refund_time, ci.create_time)) >= #{startDate}
AND DATE(COALESCE(ci.charge_time, ci.refund_time, ci.create_time)) <= #{endDate}
AND ci.charge_method = #{chargeMethod}
AND ci.status = #{status}
ORDER BY COALESCE(ci.charge_time, ci.refund_time, ci.create_time) DESC
